import type { Meta, StoryObj } from '@storybook/nextjs-vite';

import { ThematiqueScope } from '@client/composants/shared/thematique-scope';

import { iconesThematiques } from '../_data/icones-thematiques';
import {
  type ThematiqueReferentiel,
  thematiquesEngagement,
} from '../_data/referentiel-engagement';

/**
 * Catalogue des **thématiques d'engagement**
 *
 * Source de vérité : le référentiel Hygraph (champ `etiquette` de chaque
 * `actionsCategory` de type « Entreprise »). Chaque thématique porte un picto
 * (Magicoon, DDR-003) et deux couleurs (DDR-004) :
 *
 * - `couleurAccent` (color1) : teinte foncée — texte, picto, bordure ;
 * - `couleurPastel` (color2) : teinte claire — fond de section thématique.
 */

function PastilleHex({ hex, label }: { hex: string; label: string }) {
  return (
    <span className="inline-flex items-center gap-1.5 text-xs text-(--color-dsfr-text-mention-grey)">
      <span
        aria-hidden
        className="size-4 rounded-full border border-black/10"
        style={{ background: hex }}
      />
      <span className="font-medium">{label}</span>
      <code>{hex}</code>
    </span>
  );
}

function CarteThematique({
  thematique,
}: {
  thematique: ThematiqueReferentiel;
}) {
  const Picto = iconesThematiques[thematique.iconMagicoon];
  return (
    <ThematiqueScope
      etiquette={{
        color1: thematique.couleurAccent,
        color2: thematique.couleurPastel,
      }}
      className="flex flex-col overflow-hidden rounded-xl border border-(--color-dsfr-border-default-grey)"
    >
      <div className="flex items-center gap-3 bg-(--thematique-bg) p-4">
        <span
          aria-hidden
          className="flex size-11 shrink-0 items-center justify-center rounded-lg bg-white/70 text-(--thematique-main)"
        >
          {Picto ? <Picto className="size-6" /> : null}
        </span>
        <span className="text-base font-bold text-(--thematique-main)">
          {thematique.nom}
        </span>
      </div>
      <div className="flex flex-1 flex-col gap-2 bg-white p-4">
        <PastilleHex hex={thematique.couleurAccent} label="main (color1)" />
        <PastilleHex hex={thematique.couleurPastel} label="bg (color2)" />
        <div className="mt-1 flex flex-wrap items-center gap-x-3 gap-y-1 text-xs text-(--color-dsfr-text-mention-grey)">
          <span>
            picto <code>{thematique.iconMagicoon}</code>
          </span>
          <span>
            {thematique.engagements.length} engagement
            {thematique.engagements.length > 1 ? 's' : ''}
          </span>
        </div>
      </div>
    </ThematiqueScope>
  );
}

function CatalogueThematiques() {
  return (
    <div className="flex flex-col gap-6 bg-dsfr-background-default-grey p-6 font-sans">
      <div className="flex max-w-3xl flex-col gap-2">
        <h1 className="text-2xl font-bold text-(--color-dsfr-text-title-grey)">
          Thématiques d’engagement
        </h1>
        <p className="text-sm leading-6 text-(--color-dsfr-text-mention-grey)">
          {thematiquesEngagement.length} thématiques réelles du référentiel
          (type « Entreprise »), avec leur picto Magicoon et leur couple de
          couleurs. Chaque carte est enveloppée d’un{' '}
          <code>ThematiqueScope</code> : le fond pastel est{' '}
          <code>--thematique-bg</code>, le picto et le texte sont{' '}
          <code>--thematique-main</code>.
        </p>
      </div>
      <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3">
        {thematiquesEngagement.map((thematique) => (
          <CarteThematique key={thematique.id} thematique={thematique} />
        ))}
      </div>
    </div>
  );
}

const meta: Meta<typeof CatalogueThematiques> = {
  title: 'Design system/Fondations/Thématiques',
  component: CatalogueThematiques,
  tags: ['autodocs'],
  parameters: {
    espace: 'vitrine',
    layout: 'fullscreen',
    docs: {
      description: {
        component: [
          'Catalogue des thématiques réelles du référentiel d’engagement',
          '(Hygraph, type « Entreprise »). Pour chaque thématique : picto',
          'Magicoon (DDR-003), couleur d’accent (color1) et couleur pastel',
          '(color2, DDR-004), et nombre d’engagements rattachés.',
          '',
          'Les couleurs sont diffusées via `ThematiqueScope` (DDR-004) :',
          'rôles `--thematique-main` / `--thematique-bg`, jamais de hex en dur.',
          'Données partagées avec les modèles de page du scénario 1 via',
          '`apps/storybook/stories/_data/referentiel-engagement.ts`.',
        ].join('\n'),
      },
    },
  },
};

export default meta;

type Story = StoryObj<typeof CatalogueThematiques>;

export const Defaut: Story = {
  name: 'Catalogue',
};

