import type { Meta, StoryObj } from '@storybook/nextjs-vite';

import { AppSidebarOnboarding } from '@client/composants/espace-membre/app-sidebar-onboarding';
import {
  AppSidebarShell,
  SidebarNavGroupView,
} from '@client/composants/espace-membre/app-sidebar-shell';
import { EspaceMembreSidebarProvider } from '@client/composants/espace-membre/espace-membre-sidebar-provider';
import { getSidebarNavGroups } from '@client/composants/espace-membre/sidebar-nav.config';

import { SidebarProvider } from 'shadcn/components/ui/sidebar';

/**
 * Composition **espace membre moderne** : la barre latérale de navigation
 * complète (logo, groupes, items actif / désactivé, repli en rail d'icônes).
 *
 * Sources : `app-sidebar-shell.tsx` (coquille + items) et `sidebar-nav.config.ts`
 * (groupes de navigation). En production, `AppSidebar` injecte l'item actif
 * depuis `usePathname` ; ici on le fixe explicitement pour l'aperçu.
 *
 * Le contexte d'ouverture / repli est fourni par `SidebarProvider`.
 */

const SIRET = '12345678900012';
const groupes = getSidebarNavGroups({
  siret: SIRET,
  isCompanyHeadOffice: true,
});
// Item actif : « Mes engagements » (groupe Engagement).
const urlActive = `/espace-membre-v2/${SIRET}/mes-engagements`;

function SidebarPreview({ collapsed }: { collapsed?: boolean }) {
  return (
    <SidebarProvider defaultOpen={!collapsed}>
      <div className="flex h-160 bg-dsfr-background-alt-grey">
        <AppSidebarShell>
          {groupes.map((groupe) => (
            <SidebarNavGroupView
              key={groupe.label}
              group={groupe}
              activeUrl={urlActive}
            />
          ))}
        </AppSidebarShell>
      </div>
    </SidebarProvider>
  );
}

const meta: Meta<typeof SidebarPreview> = {
  title: 'Design system/Compositions/Webapp/Sidebar',
  component: SidebarPreview,
  tags: ['autodocs'],
  parameters: {
    espace: 'espace-membre',
    layout: 'fullscreen',
    docs: {
      description: {
        component: [
          "Barre latérale complète de l'espace membre moderne.",
          "Affiche les groupes de navigation, l'item actif, les items",
          "désactivés et le bouton de repli en rail d'icônes.",
        ].join('\n'),
      },
    },
  },
};

export default meta;
type Story = StoryObj<typeof SidebarPreview>;

export const Deployee: Story = {
  name: 'Déployée',
  args: { collapsed: false },
};

export const Repliee: Story = {
  name: 'Repliée (rail d’icônes)',
  args: { collapsed: true },
};

/**
 * Variante **onboarding** : la sidebar affichée tant que l'entreprise n'a pas
 * terminé son embarquement. Items franchissables badgés « new », items à
 * venir désactivés. Rend le vrai `AppSidebarOnboarding` (l'item actif vient de
 * `usePathname`, mocké à `/` en Storybook — aucun item surligné ici).
 */
export const Onboarding: Story = {
  name: 'Variante onboarding',
  render: () => (
    <EspaceMembreSidebarProvider>
      <div className="flex h-160 bg-dsfr-background-alt-grey">
        <AppSidebarOnboarding
          siret={SIRET}
          onboarding={{
            hasProfilComplet: false,
            hasEngagements: false,
            hasClub: false,
          }}
        />
      </div>
    </EspaceMembreSidebarProvider>
  ),
};

