import type { Meta, StoryObj } from '@storybook/nextjs-vite';
import {
  RiBuildingLine,
  RiEarthLine,
  RiGroupLine,
  RiPencilLine,
} from 'react-icons/ri';

import {
  AppSidebarShell,
  SidebarNavGroupView,
} from '@client/composants/espace-membre/app-sidebar-shell';
import { EspaceMembreHeaderView } from '@client/composants/espace-membre/espace-membre-header-view';
import { EspaceMembreSidebarProvider } from '@client/composants/espace-membre/espace-membre-sidebar-provider';
import { PageContent } from '@client/composants/espace-membre/page-content';
import { PageHeader } from '@client/composants/espace-membre/page-header';
import { getSidebarNavGroups } from '@client/composants/espace-membre/sidebar-nav.config';
import BuildingIcon from '@client/icons/magicoon/building.svg';

import {
  Breadcrumb,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbList,
  BreadcrumbPage,
  BreadcrumbSeparator,
} from 'shadcn/components/ui/breadcrumb';
import { Button } from 'shadcn/components/ui/button';
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
} from 'shadcn/components/ui/card';
import {
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
} from 'shadcn/components/ui/tabs';

/**
 * Modèle de page **espace membre moderne** (couche 04) : le **layout complet**.
 *
 * Assemble toutes les pièces du chrome de l'espace membre v2 dans leur
 * disposition réelle :
 *
 * - `EspaceMembreSidebarProvider` (largeurs `--sidebar-width` à 260px) ;
 * - la barre latérale `AppSidebarShell` + groupes (`sidebar-nav.config`) ;
 * - le header global `EspaceMembreHeaderView` (fil d'Ariane + notifications +
 *   `AvatarDropdown`) ;
 * - le `PageHeader` (icône Magicoon 24px, onglets `variant="line"`) + le
 *   `PageContent` scrollable.
 *
 * C'est la vue de référence pour comprendre comment les briques s'imbriquent.
 */

const SIRET = '12345678900012';
const groupes = getSidebarNavGroups({
  siret: SIRET,
  isCompanyHeadOffice: true,
});
const urlActive = `/espace-membre-v2/${SIRET}/informations-entreprise`;

function FilAriane() {
  return (
    <Breadcrumb>
      <BreadcrumbList>
        <BreadcrumbItem>
          <BreadcrumbLink href="#">Espace membre</BreadcrumbLink>
        </BreadcrumbItem>
        <BreadcrumbSeparator>/</BreadcrumbSeparator>
        <BreadcrumbItem>
          <BreadcrumbPage>Informations entreprise</BreadcrumbPage>
        </BreadcrumbItem>
      </BreadcrumbList>
    </Breadcrumb>
  );
}

function LayoutComplet() {
  return (
    <EspaceMembreSidebarProvider>
      <div className="flex h-200 w-full bg-dsfr-background-alt-grey">
        <AppSidebarShell>
          {groupes.map((groupe) => (
            <SidebarNavGroupView
              key={groupe.label}
              group={groupe}
              activeUrl={urlActive}
            />
          ))}
        </AppSidebarShell>
        <div className="flex min-w-0 flex-1 flex-col">
          <EspaceMembreHeaderView
            breadcrumb={<FilAriane />}
            nomUtilisateur="Camille Durand"
            nomEntreprise="Entreprise exemple SAS"
          />
          <main
            className="@container/main min-h-0 flex-1 overflow-auto bg-dsfr-background-alt-grey"
          >
            <div className="mx-auto flex w-full max-w-7xl flex-col items-start">
              <Tabs defaultValue="informations" className="contents">
                <PageHeader
                  icon={BuildingIcon}
                  title="Informations entreprise"
                  actions={
                    <Button type="button" size="sm">
                      <RiPencilLine aria-hidden className="size-4" />
                      Modifier
                    </Button>
                  }
                  tabs={
                    <TabsList variant="line">
                      <TabsTrigger value="informations">
                        <RiBuildingLine />
                        Informations
                      </TabsTrigger>
                      <TabsTrigger value="membres">
                        <RiGroupLine />
                        Membres
                      </TabsTrigger>
                      <TabsTrigger value="fiche-publique">
                        <RiEarthLine />
                        Fiche publique
                      </TabsTrigger>
                    </TabsList>
                  }
                />
                <PageContent>
                  <TabsContent value="informations" className="contents">
                    <Card className="col-span-12 md:col-span-6">
                      <CardHeader>
                        <CardTitle className="text-lg">Identité</CardTitle>
                      </CardHeader>
                      <CardContent className="text-muted-foreground text-sm">
                        Raison sociale, SIRET, secteur d'activité et
                        coordonnées de l'entreprise.
                      </CardContent>
                    </Card>
                    <Card className="col-span-12 md:col-span-6">
                      <CardHeader>
                        <CardTitle className="text-lg">Référent·e</CardTitle>
                      </CardHeader>
                      <CardContent className="text-muted-foreground text-sm">
                        Contact principal de l'entreprise pour Les entreprises
                        s'engagent.
                      </CardContent>
                    </Card>
                  </TabsContent>
                  <TabsContent value="membres" className="col-span-full">
                    <p className="text-muted-foreground text-sm">
                      Liste des membres rattachés à l'entreprise.
                    </p>
                  </TabsContent>
                  <TabsContent
                    value="fiche-publique"
                    className="col-span-full"
                  >
                    <p className="text-muted-foreground text-sm">
                      Paramètres et aperçu de la fiche publique.
                    </p>
                  </TabsContent>
                </PageContent>
              </Tabs>
            </div>
          </main>
        </div>
      </div>
    </EspaceMembreSidebarProvider>
  );
}

const meta: Meta<typeof LayoutComplet> = {
  title: 'Design system/Modèles de page/Webapp/Layout complet',
  component: LayoutComplet,
  tags: ['autodocs'],
  parameters: {
    espace: 'espace-membre',
    layout: 'fullscreen',
    docs: {
      description: {
        component: [
          "Layout complet de l'espace membre moderne : sidebar + header global",
          '+ `PageHeader` (icône Magicoon, onglets `line`) + `PageContent`.',
          '',
          'Toutes les briques sont les composants réels de',
          '`@client/composants/espace-membre/*`. Le header utilise la vue',
          'présentationnelle `EspaceMembreHeaderView` (le Server Component réel',
          'lit la session + Prisma).',
        ].join('\n'),
      },
    },
  },
};

export default meta;
type Story = StoryObj<typeof LayoutComplet>;

export const Defaut: Story = {
  name: 'Layout complet',
};

